
(() => {
  "use strict";

  /* ── Output-signal "settle" morph ───────────────────────────────────────
     As .trigger scrolls into view, scrub-morph the garbled Output meter into
     the clean green spikes — shape + colour. The meter is built at runtime by
     utils.js (svglink), so we wait for its <svg> tiles before wiring GSAP.
     Both scroll tiles morph in lockstep, so the seamless loop is preserved
     and the horizontal scroll keeps running underneath. */

  // --- Which meter morphs. Edit if you rename the asset / use a class. ------
  const METER_SELECTOR = '.svglink-scroller[svglink*="red"]';
  const TRIGGER_SELECTOR = ".trigger";

  // --- Target geometry (252×132 viewBox) — the clean, settled waveform. -----
  const FILL_D = "M0 121.8L6.46 7.71997H12.92H19.38H25.85H32.31L38.77 121.8H45.23H51.69H58.15H64.62L71.08 7.71997H77.54H84H90.46H96.92L103.38 121.8H109.85H116.31H122.77H129.23L135.69 7.71997H142.15H148.62H155.08H161.54L168 121.8H174.46H180.92H187.38H193.85L200.31 7.71997H206.77H213.23H219.69H226.15L232.62 121.8H239.08H245.54H252V128H0V121.8Z";
  const LINE_D = "M0 121.8L6.46 7.71997H12.92H19.38H25.85H32.31L38.77 121.8H45.23H51.69H58.15H64.62L71.08 7.71997H77.54H84H90.46H96.92L103.38 121.8H109.85H116.31H122.77H129.23L135.69 7.71997H142.15H148.62H155.08H161.54L168 121.8H174.46H180.92H187.38H193.85L200.31 7.71997H206.77H213.23H219.69H226.15L232.62 121.8H239.08H245.54H252";

  // --- Target colours (green = #7FB53F). ------------------------------------
  const GREEN = "#7FB53F";
  const SOURCE_STROKE = "#D73228";          // red stroke utils.js renders
  const GLOW_STROKE = "rgb(191, 218, 159)"; // lighten(#7FB53F, .5)
  const GLOW_FILTER =
    "drop-shadow(rgba(127, 181, 63, 0.75) 0px 0px 3px) drop-shadow(rgba(127, 181, 63, 0.45) 0px 0px 8px)";

  function build(meter) {
    if (typeof gsap === "undefined" || !gsap.plugins || !gsap.plugins.morphSVG) {
      console.warn("[output-morph] gsap / MorphSVGPlugin not loaded");
      return;
    }
    gsap.registerPlugin(MorphSVGPlugin, ScrollTrigger);

    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: TRIGGER_SELECTOR,
        start: "top bottom",
        end: "top center",
        scrub: true,
      },
    });

    meter.querySelectorAll(".svglink-track > svg").forEach((svg) => {
      const fill = svg.querySelector('path[fill^="url("]');
      const line = svg.querySelector(`path[stroke="${SOURCE_STROKE}"]`);
      const glow = svg.querySelector("path.svglink-trace");
      const stops = svg.querySelectorAll("linearGradient stop");

      if (fill) tl.to(fill, { morphSVG: FILL_D, ease: "none" }, 0);
      if (line) tl.to(line, { morphSVG: LINE_D, attr: { stroke: GREEN }, ease: "none" }, 0);
      if (glow)
        tl.to(glow, {
          morphSVG: LINE_D,
          attr: { stroke: GLOW_STROKE },
          filter: GLOW_FILTER,
          ease: "none",
        }, 0);
      stops.forEach((s) => tl.to(s, { attr: { "stop-color": GREEN }, ease: "none" }, 0));
    });

    ScrollTrigger.refresh(); // layout settled after async inline
  }

  // utils.js inlines the meter asynchronously — wait for its <svg> paths.
  function whenInlined(meter, cb) {
    const ready = () => meter.querySelector(".svglink-track > svg path");
    if (ready()) return cb(meter);

    let done = false;
    const fire = () => {
      if (done || !ready()) return;
      done = true;
      obs.disconnect();
      cb(meter);
    };
    const obs = new MutationObserver(fire);
    obs.observe(meter, { childList: true, subtree: true });
    setTimeout(fire, 8000); // safety net if the observer never sees it
  }

  function init() {
    const meter = document.querySelector(METER_SELECTOR);
    if (meter) whenInlined(meter, build);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
